"""
FastAPI Application for Machine Learning Algorithms
"""

from fastapi import FastAPI, HTTPException
from fastapi.middleware.cors import CORSMiddleware
from pydantic import BaseModel
from typing import List, Any, Optional
import numpy as np
import pandas as pd

from skilearn.algorithms import CandidateElimination, FindS, HypothesisTesting

app = FastAPI(
    title="Skilearn - Machine Learning Algorithms API",
    description="FastAPI application for Candidate Elimination, Find-S, and Hypothesis Testing algorithms",
    version="0.1.0"
)

# Add CORS middleware
app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)


# Request/Response Models
class FindSRequest(BaseModel):
    features: List[List[Any]]
    labels: List[Any]


class CandidateEliminationRequest(BaseModel):
    features: List[List[Any]]
    labels: List[Any]


class HypothesisTestRequest(BaseModel):
    test_type: str  # 't_test', 'two_sample_t_test', 'chi_square', 'normality'
    data: List[float]
    data2: Optional[List[float]] = None
    mu0: Optional[float] = 0
    alternative: Optional[str] = 'two-sided'
    expected: Optional[List[float]] = None


@app.get("/")
async def root():
    return {
        "message": "MGAI - Machine Learning Algorithms API",
        "version": "0.1.0",
        "endpoints": {
            "find_s": "/api/find-s",
            "candidate_elimination": "/api/candidate-elimination",
            "hypothesis_testing": "/api/hypothesis-testing"
        }
    }


@app.get("/health")
async def health_check():
    return {"status": "healthy"}


@app.post("/api/find-s")
async def find_s_endpoint(request: FindSRequest):
    """
    Apply Find-S algorithm to find the most specific hypothesis.
    
    Args:
        request: Request containing features and labels
    
    Returns:
        The learned hypothesis
    """
    try:
        # Convert to numpy arrays
        X = np.array(request.features)
        y = np.array(request.labels)
        
        # Apply Find-S
        find_s = FindS()
        hypothesis = find_s.fit(X, y)
        
        return {
            "hypothesis": hypothesis,
            "message": "Find-S algorithm completed successfully"
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/api/candidate-elimination")
async def candidate_elimination_endpoint(request: CandidateEliminationRequest):
    """
    Apply Candidate Elimination algorithm to find the version space.
    
    Args:
        request: Request containing features and labels
    
    Returns:
        The version space (general and specific boundaries)
    """
    try:
        # Convert to numpy arrays
        X = np.array(request.features)
        y = np.array(request.labels)
        
        # Apply Candidate Elimination
        ce = CandidateElimination()
        general, specific, all_hypotheses = ce.fit(X, y)
        
        return {
            "general_boundary": general,
            "specific_boundary": specific,
            "version_space_size": len(all_hypotheses),
            "message": "Candidate Elimination algorithm completed successfully"
        }
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


@app.post("/api/hypothesis-testing")
async def hypothesis_testing_endpoint(request: HypothesisTestRequest):
    """
    Perform statistical hypothesis testing.
    
    Args:
        request: Request containing test type, data, and parameters
    
    Returns:
        Test results including statistic, p-value, and conclusion
    """
    try:
        data = np.array(request.data)
        ht = HypothesisTesting()
        
        if request.test_type == 't_test':
            result = ht.t_test(data, request.mu0, request.alternative)
        
        elif request.test_type == 'two_sample_t_test':
            if request.data2 is None:
                raise ValueError("data2 is required for two-sample t-test")
            data2 = np.array(request.data2)
            result = ht.two_sample_t_test(data, data2, request.alternative)
        
        elif request.test_type == 'chi_square':
            expected = np.array(request.expected) if request.expected else None
            result = ht.chi_square_test(data, expected)
        
        elif request.test_type == 'normality':
            result = ht.normality_test(data)
        
        else:
            raise ValueError(f"Unknown test type: {request.test_type}")
        
        return {
            "test_type": request.test_type,
            "results": result,
            "message": "Hypothesis test completed successfully"
        }
    
    except Exception as e:
        raise HTTPException(status_code=400, detail=str(e))


if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8000)

